// score を z-score 化（baseline 想定からの偏差）
export function zScore(axis: string, raw: number): number {
  const m = BASELINE_MEAN[axis] ?? 0
  const s = BASELINE_STD[axis] ?? 1
  return (raw - m) / s
}

// 標準正規分布の CDF 近似（Abramowitz-Stegun）。z-score → 累積確率（0..1）。
function normalCdf(z: number): number {
  const sign = z < 0 ? -1 : 1
  const x = Math.abs(z) / Math.SQRT2
  const t = 1 / (1 + 0.3275911 * x)
  const y =
    1 -
    ((((1.061405429 * t - 1.453152027) * t + 1.421413741) * t - 0.284496736) * t +
      0.254829592) *
      t *
      Math.exp(-x * x)
  return 0.5 * (1 + sign * y)
}

// raw score → 「上位何%」（1..99）。z>0 で上位（小さい数字）、z<0 で下位（大きい数字）
export function topPercentile(axis: string, raw: number): number {
  const z = zScore(axis, raw)
  const p = normalCdf(z) // 累積確率（小=低スコア、大=高スコア）
  const topPct = Math.round((1 - p) * 100)
  return Math.min(99, Math.max(1, topPct))
}

// 全 personality 軸（attract/self/other 系を除く）から最も極端（|z| 大）な top N を返す。
// 結果ページの「あなたの最希少ポイント」用。
const PERSONALITY_AXES: readonly string[] = [
  "lowTempEmotion",
  "lateNightVibe",
  "urbanSense",
  "dailyLifeFeel",
  "awkwardness",
  "neglectTolerance",
  "loveExpression",
  "lineTemperature",
  "humanity",
  "emotionalInstabilityTolerance",
  "silenceDependency",
  "innocenceTolerance",
  "conversationDensity",
  "distanceSense",
  "independence",
  "vibeMatch",
  "edginessTolerance",
  "caretakerDependency",
  "understandDesire",
  "saveDesire",
]

export interface RarityHighlight {
  readonly axis: string
  readonly z: number
  readonly topPercent: number // 1..99
  readonly direction: "high" | "low"
}

export function getRarityHighlights(
  scores: Readonly<Record<string, number>>,
  count: number = 3
): readonly RarityHighlight[] {
  return PERSONALITY_AXES.map((axis) => {
    const raw = scores[axis] ?? 0
    const z = zScore(axis, raw)
    return {
      axis,
      z,
      topPercent: topPercentile(axis, raw),
      direction: z >= 0 ? ("high" as const) : ("low" as const),
    }
  })
    .sort((a, b) => Math.abs(b.z) - Math.abs(a.z))
    .slice(0, count)
}

