// 軸の "独立な信号としての重み"。MBTI 次元軸（attract系）は 1.0、
// personality 軸は AXIS_UNIQUENESS をそのまま使う。
export function axisUniqueness(axis: string): number {
  if (axis.startsWith("attract")) return 1.0
  return AXIS_UNIQUENESS[axis] ?? 1.0
}

